def tarjan(graph):
  index = 0
  stack = []
  lowlinks = {}
  index_map = {}
  result = []
  for v in graph:
    if v not in index_map:
      strongconnect(v, index, stack, lowlinks, index_map, result)
  return result

def strongconnect(v, index, stack, lowlinks, index_map, result):
  index_map[v] = index
  lowlinks[v] = index
  index += 1
  stack.append(v)
  for w in graph[v]:
    if w not in index_map:
      strongconnect(w, index, stack, lowlinks, index_map, result)
      lowlinks[v] = min(lowlinks[v], lowlinks[w])
    elif w in stack:
      lowlinks[v] = min(lowlinks[v], index_map[w])
  if lowlinks[v] == index_map[v]:
    connected_component = []
    while True:
      w = stack.pop()
      connected_component.append(w)
      if w == v:
        break
    result.append(connected_component)
